import { supabase } from '../lib/supabase';
import { Customer, Product, Order } from '../types';

export const dbService = {
  // --- CUSTOMERS ---
  async getCustomers(): Promise<Customer[]> {
    const { data, error } = await supabase!
      .from('customers')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch customers:", error);
      throw error;
    }
    return data || [];
  },

  async upsertCustomer(customer: Customer) {
    const { error } = await supabase!
      .from('customers')
      .upsert(customer);

    if (error) {
      console.error("Error upsert customer:", error);
      throw error;
    }
  },

  async deleteCustomer(id: string) {
    const { error } = await supabase!
      .from('customers')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete customer:", error);
      throw error;
    }
  },

  // --- PRODUCTS ---
  async getProducts(): Promise<Product[]> {
    const { data, error } = await supabase!
      .from('products')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch products:", error);
      throw error;
    }
    return data || [];
  },

  async upsertProduct(product: Product) {
    const { error } = await supabase!
      .from('products')
      .upsert(product);

    if (error) {
      console.error("Error upsert product:", error);
      throw error;
    }
  },

  async deleteProduct(id: string) {
    const { error } = await supabase!
      .from('products')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete product:", error);
      throw error;
    }
  },

  // --- ORDERS ---
  async getOrders(): Promise<Order[]> {
    const { data, error } = await supabase!
      .from('orders')
      .select('*')
      .order('orderDate', { ascending: false });

    if (error) {
      console.error("Error fetch orders:", error);
      throw error;
    }
    return data || [];
  },

  async upsertOrder(order: Order) {
    console.log("Attempting to upsert order:", order);
    const { error } = await supabase!
      .from('orders')
      .upsert(order);

    if (error) {
      console.error("SUPABASE ERROR (upsertOrder):", error.message, error.details, error.hint);
      throw new Error(error.message || "Gagal menyimpan order ke database");
    }
  },

  async deleteOrder(id: string) {
    const { error } = await supabase!
      .from('orders')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete order:", error);
      throw error;
    }
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, User, 
  Package, Check, CreditCard, Edit3, X, Calendar, Loader2, AlertCircle
} from 'lucide-react';
import { AppState, Order, OrderItem, Product, OrderStatus, LocationType, PaymentRecord } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => Promise<any>;
  onUpdateOrder: (o: Order) => Promise<any>;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onUpdateOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);

  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');
  const [orderDate, setOrderDate] = useState(new Date().toISOString().split('T')[0]);

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);

  // Sync state when editing
  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId || '');
      setOrderItems(editingOrder.items ? editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })) : []);
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setOrderDate(new Date(editingOrder.orderDate).toISOString().split('T')[0]);
      setIsFormOpen(true);
      setFormError(null);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? (Number(product.priceLuarKota) || 0) : (Number(product.priceJakarta) || 0);
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * Number(item.qty));
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + (Number(p.amount) || 0), 0);
  }, [payments]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError(null);

    if (isSubmitting) return;

    // VALIDASI DASAR
    if (!selectedCustomerId || !selectedCustomer) {
      setFormError("Silakan pilih pelanggan terlebih dahulu.");
      return;
    }
    if (orderItems.length === 0) {
      setFormError("Tambahkan minimal satu barang ke dalam pesanan.");
      return;
    }

    setIsSubmitting(true);
    try {
      // Mapping Items dengan konversi data numerik yang ketat
      const items: OrderItem[] = orderItems.map(oi => {
        const p = state.products.find(product => product.id === oi.productId);
        if (!p) throw new Error(`Produk dengan ID ${oi.productId} tidak ditemukan`);

        const price = calculateItemPrice(p, selectedCustomer.type);
        return {
          id: Math.random().toString(36).substr(2, 9),
          productId: p.id,
          name: p.name,
          quantity: Number(oi.qty),
          unitPrice: Number(price)
        };
      });

      const finalSubtotal = Number(calculatedSubtotal);
      const finalPaid = Number(currentTotalPaid);
      const finalRemaining = Math.max(0, finalSubtotal - finalPaid);

      const orderData: Order = {
        id: editingOrder ? editingOrder.id : `ord_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
        customerId: selectedCustomerId,
        customerName: selectedCustomer.name,
        customerEmail: selectedCustomer.email || '',
        customerType: selectedCustomer.type,
        customerAddress: selectedCustomer.address || '',
        orderDate: new Date(orderDate).toISOString(),
        status: finalRemaining <= 0 ? OrderStatus.PAID : OrderStatus.PENDING,
        items: items,
        subtotal: finalSubtotal,
        downPayment: finalPaid,
        payments: payments,
        total: finalRemaining,
        notes: notes.trim()
      };

      if (editingOrder) {
        await onUpdateOrder(orderData);
      } else {
        await onAddOrder(orderData);
      }

      resetForm();
    } catch (err: any) {
      console.error("Submit order logic error:", err);
      setFormError(err.message || "Gagal menyimpan data. Pastikan tabel 'orders' sudah ada di Supabase.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const addPayment = () => {
    const amount = Number(newPaymentAmount);
    if (isNaN(amount) || amount <= 0) {
      alert("Masukkan nominal pembayaran yang valid");
      return;
    }
    const newRecord: PaymentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      amount: amount,
      date: new Date().toISOString(),
      note: newPaymentNote.trim() || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
    };
    setPayments([...payments, newRecord]);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setOrderDate(new Date().toISOString().split('T')[0]);
    setShowPaymentInput(false);
    setIsSubmitting(false);
    setFormError(null);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-slate-800 tracking-tight">Daftar Transaksi</h2>
          <p className="text-slate-500 text-xs md:text-sm font-medium">Buat invoice dan kelola piutang pelanggan</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="w-full sm:w-auto bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95"
        >
          <Plus size={18} /> Buat Order
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-6 md:p-10 animate-in slide-in-from-top-4 duration-500">
           <div className="flex justify-between items-center mb-10">
             <div>
               <h3 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{editingOrder ? 'Koreksi Pesanan' : 'Input Pesanan Baru'}</h3>
               <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mt-1">{editingOrder ? editingOrder.invoiceNumber : 'Invoice Otomatis'}</p>
             </div>
             <button onClick={resetForm} disabled={isSubmitting} className="p-3 hover:bg-slate-50 rounded-2xl text-slate-400 transition-colors disabled:opacity-30"><X size={24}/></button>
           </div>

           {formError && (
             <div className="mb-8 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in fade-in zoom-in-95">
                <AlertCircle size={20} />
                <p className="text-xs font-black uppercase tracking-tight">{formError}</p>
             </div>
           )}

           <form onSubmit={handleSubmit} className="space-y-10">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                <div className="space-y-8">
                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <Calendar size={14} className="text-indigo-500"/> 1. Waktu Transaksi
                    </h3>
                    <input 
                      required
                      type="date"
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-indigo-500/10 bg-slate-50 outline-none font-bold text-sm transition-all"
                      value={orderDate}
                      onChange={e => setOrderDate(e.target.value)}
                    />
                  </div>

                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <User size={14} className="text-indigo-500"/> 2. Identitas Pelanggan
                    </h3>
                    <select 
                      required
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-indigo-500/10 bg-slate-50 outline-none font-bold text-sm appearance-none cursor-pointer transition-all"
                      value={selectedCustomerId}
                      onChange={e => setSelectedCustomerId(e.target.value)}
                    >
                      <option value="">-- Cari Nama Pelanggan --</option>
                      {state.customers.map(c => (
                        <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                      ))}
                    </select>
                    {state.customers.length === 0 && (
                      <p className="text-[9px] text-amber-600 font-black uppercase">* Belum ada pelanggan terdaftar. Silakan ke menu Pelanggan.</p>
                    )}
                  </div>
                </div>

                <div className="space-y-4">
                   <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <Package size={14} className="text-indigo-500"/> 3. Detail Barang
                  </h3>
                  <div className="space-y-3 max-h-[350px] overflow-y-auto pr-2 no-scrollbar border-2 border-dashed border-slate-100 p-4 rounded-3xl bg-slate-50/30">
                    {state.products.length === 0 && (
                      <div className="py-10 text-center opacity-30 italic text-xs font-bold uppercase tracking-widest">Katalog barang kosong</div>
                    )}
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                          existing ? 'bg-white border-indigo-200 shadow-xl shadow-indigo-500/5' : 'bg-white/50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-4">
                             <p className="text-xs font-black text-slate-800 truncate">{p.name}</p>
                             <p className="text-[9px] text-slate-400 font-black uppercase tracking-wider mt-1">
                               Rp {(selectedCustomer ? calculateItemPrice(p, selectedCustomer.type) : Number(p.priceJakarta)).toLocaleString()}
                             </p>
                           </div>
                           <div className="flex items-center gap-3 shrink-0">
                             {existing && (
                               <div className="flex items-center bg-indigo-50 rounded-xl px-2">
                                 <span className="text-[8px] font-black text-indigo-400 uppercase mr-1">Qty</span>
                                 <input 
                                   type="number"
                                   min="1"
                                   className="w-10 py-2 border-none text-xs font-black text-center outline-none bg-transparent text-indigo-700"
                                   value={existing.qty}
                                   onChange={e => {
                                     const val = Math.max(1, parseInt(e.target.value) || 1);
                                     setOrderItems(orderItems.map(i => i.productId === p.id ? { ...i, qty: val } : i));
                                   }}
                                 />
                               </div>
                             )}
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
                                 existing ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white text-slate-300 border border-slate-200 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={18} /> : <Plus size={18} />}
                             </button>
                           </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pt-10 border-t border-slate-100">
                <div className="space-y-6">
                  <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <CreditCard size={14} className="text-indigo-500"/> 4. Pembayaran / DP
                    </h3>
                    <button 
                      type="button" 
                      onClick={() => setShowPaymentInput(!showPaymentInput)}
                      className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl border border-indigo-100 hover:bg-indigo-100 transition-all active:scale-95"
                    >
                      {showPaymentInput ? 'Batal' : '+ Tambah Bayar'}
                    </button>
                  </div>

                  {showPaymentInput && (
                    <div className="bg-slate-900 p-6 rounded-3xl space-y-4 shadow-2xl animate-in fade-in zoom-in-95 duration-300">
                      <div className="grid grid-cols-1 gap-4">
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Nominal Pembayaran</label>
                          <div className="relative">
                             <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 text-[10px] font-black">RP</span>
                             <input 
                              type="number"
                              placeholder="0"
                              className="w-full pl-10 pr-5 py-3 rounded-2xl bg-white/10 border border-white/10 text-white text-sm font-black outline-none focus:border-indigo-500 transition-all"
                              value={newPaymentAmount || ''}
                              onChange={e => setNewPaymentAmount(Number(e.target.value))}
                            />
                          </div>
                        </div>
                        <div className="space-y-1">
                           <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Keterangan (Contoh: DP 50%)</label>
                           <input 
                            type="text"
                            placeholder="Catatan pembayaran..."
                            className="w-full px-5 py-3 rounded-2xl bg-white/10 border border-white/10 text-white text-sm font-medium outline-none focus:border-indigo-500 transition-all"
                            value={newPaymentNote}
                            onChange={e => setNewPaymentNote(e.target.value)}
                          />
                        </div>
                      </div>
                      <button 
                        type="button" 
                        onClick={addPayment}
                        className="w-full bg-indigo-600 text-white py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20"
                      >
                        Konfirmasi Pembayaran
                      </button>
                    </div>
                  )}

                  <div className="space-y-3">
                    {payments.map((p) => (
                      <div key={p.id} className="flex justify-between items-center p-5 bg-slate-50 border border-slate-100 rounded-3xl">
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-2xl bg-emerald-500 text-white flex items-center justify-center shadow-lg shadow-emerald-100">
                            <Check size={18}/>
                          </div>
                          <div>
                            <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{p.note}</p>
                            <p className="text-[10px] text-slate-400 font-bold">{new Date(p.date).toLocaleDateString('id-ID')}</p>
                          </div>
                        </div>
                        <p className="text-sm font-black text-slate-900">Rp {p.amount.toLocaleString()}</p>
                      </div>
                    ))}
                    {payments.length === 0 && (
                      <div className="text-center py-10 text-[10px] text-slate-300 font-black uppercase tracking-[0.2em] border-2 border-dashed border-slate-50 rounded-[2rem]">
                        Belum ada pembayaran masuk
                      </div>
                    )}
                  </div>
                </div>

                <div className="space-y-4">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Instruksi / Catatan Tambahan</h3>
                  <textarea 
                    className="w-full px-6 py-5 rounded-[2rem] border border-slate-200 bg-slate-50 outline-none text-sm font-medium h-full min-h-[200px] focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-inner resize-none"
                    placeholder="Tulis catatan di sini (misal: pengiriman hari rabu, packing kayu, dll)..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
             </div>

             <div className="flex flex-col lg:flex-row lg:items-center justify-between bg-slate-900 p-8 md:p-12 rounded-[3rem] text-white gap-8 shadow-2xl relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 rounded-full -mr-20 -mt-20 blur-3xl group-hover:bg-indigo-500/20 transition-all duration-700"></div>
               <div className="relative z-10">
                  <div className="flex items-center gap-4 mb-4">
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">Subtotal: Rp {calculatedSubtotal.toLocaleString()}</p>
                    <p className="text-emerald-500 text-[10px] font-black uppercase tracking-[0.2em]">Terbayar: Rp {currentTotalPaid.toLocaleString()}</p>
                  </div>
                  <h4 className="text-3xl md:text-5xl font-black tracking-tighter">
                    Tagihan: <span className="text-indigo-400">Rp {(calculatedSubtotal - currentTotalPaid).toLocaleString()}</span>
                  </h4>
               </div>
               <button 
                type="submit"
                disabled={!selectedCustomerId || orderItems.length === 0 || isSubmitting}
                className="relative z-10 w-full lg:w-auto bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-16 py-5 rounded-2xl font-black text-sm uppercase tracking-[0.2em] transition-all shadow-2xl shadow-indigo-500/30 flex items-center justify-center gap-3 active:scale-95"
               >
                 {isSubmitting ? (
                   <>
                     <Loader2 size={20} className="animate-spin" />
                     SINKRONISASI...
                   </>
                 ) : (
                   editingOrder ? 'SIMPAN PERUBAHAN' : 'SELESAIKAN ORDER'
                 )}
               </button>
             </div>
           </form>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden overflow-x-auto">
        <table className="w-full text-left min-w-[800px]">
          <thead className="bg-slate-50/50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
            <tr>
              <th className="px-8 py-6">ID Invoice</th>
              <th className="px-8 py-6">Nama Pelanggan</th>
              <th className="px-8 py-6 text-right">Nilai Belanja</th>
              <th className="px-8 py-6 text-right">Sisa Tagihan</th>
              <th className="px-8 py-6 text-center">Tindakan</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {state.orders.map(o => (
              <tr key={o.id} className="hover:bg-slate-50/50 transition-all group">
                <td className="px-8 py-6">
                  <p className="text-sm font-black text-slate-800">{o.invoiceNumber}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase">{new Date(o.orderDate).toLocaleDateString('id-ID', { dateStyle: 'medium' })}</p>
                </td>
                <td className="px-8 py-6">
                  <p className="text-sm font-bold text-slate-700 truncate max-w-[180px]">{o.customerName || 'N/A'}</p>
                  <span className="inline-flex px-2 py-0.5 rounded-lg bg-indigo-50 text-indigo-500 text-[8px] font-black uppercase tracking-widest mt-1">
                    {o.customerType}
                  </span>
                </td>
                <td className="px-8 py-6 text-right text-sm font-bold text-slate-600">
                  Rp {(o.subtotal || 0).toLocaleString()}
                </td>
                <td className="px-8 py-6 text-right">
                  <div className={`text-sm font-black flex flex-col items-end ${(o.total || 0) <= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                    <span>Rp {(o.total || 0).toLocaleString()}</span>
                    {(o.total || 0) <= 0 && <span className="text-[8px] uppercase tracking-widest bg-emerald-50 px-1.5 py-0.5 rounded-md mt-1">Lunas</span>}
                  </div>
                </td>
                <td className="px-8 py-6">
                  <div className="flex justify-center gap-2 opacity-60 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => onViewInvoice(o)} className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all" title="Lihat Invoice"><Eye size={20} /></button>
                    <button onClick={() => setEditingOrder(o)} className="p-3 text-slate-400 hover:text-amber-500 hover:bg-amber-50 rounded-2xl transition-all" title="Edit Data"><Edit3 size={20} /></button>
                    <button onClick={() => onDeleteOrder(o.id)} className="p-3 text-rose-300 hover:text-rose-600 hover:bg-rose-50 rounded-2xl transition-all" title="Hapus Permanen"><Trash2 size={20} /></button>
