import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, CheckCircle2, Info, Loader2, RefreshCw
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';
import { checkSupabaseConnection } from './lib/supabase';

interface Notification {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
}

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [initialLoading, setInitialLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);
  const loadAttempted = useRef(false);

  const showNotify = useCallback((message: string, type: 'success' | 'error' | 'info' | 'warning' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  }, []);

  const loadAllData = useCallback(async (isSilent = false) => {
    if (!isSilent) setInitialLoading(true);
    else setIsRefreshing(true);

    try {
      const connection = await checkSupabaseConnection();

      if (connection.connected) {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
        if (isSilent) showNotify("Data disinkronkan", "info");
      }
    } catch (e: any) {
      console.error("Data load error:", e);
      showNotify("Gagal sinkronisasi data: " + (e.message || "Unknown error"), "error");
    } finally {
      setInitialLoading(false);
      setIsRefreshing(false);
    }
  }, [showNotify]);

  useEffect(() => {
    if (!loadAttempted.current) {
      loadAttempted.current = true;
      loadAllData();
    }
  }, [loadAllData]);

  const setView = useCallback((view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  }, []);

  // Optimized Action: Update local state immediately after DB success
  const handleOptimizedAction = async <T,>(
    action: () => Promise<void>, 
    updateState: () => void,
    successMsg: string
  ) => {
    try {
      // Kita tidak menggunakan setIsRefreshing(true) di sini agar UI tidak "macet"
      await action();
      updateState();
      showNotify(successMsg, 'success');
      return true;
    } catch (err: any) {
      console.error("Action error:", err);
      showNotify(err.message || "Gagal memproses transaksi", 'error');
      // Jika gagal, sebaiknya re-fetch untuk memastikan data sinkron
      loadAllData(true);
      throw err;
    }
  };

  // CUSTOMERS
  const addCustomer = (c: Customer) => 
    handleOptimizedAction(
      () => dbService.upsertCustomer(c),
      () => setState(prev => ({ ...prev, customers: [c, ...prev.customers] })),
      "Pelanggan disimpan"
    );

  const updateCustomer = (c: Customer) => 
    handleOptimizedAction(
      () => dbService.upsertCustomer(c),
      () => setState(prev => ({ ...prev, customers: prev.customers.map(item => item.id === c.id ? c : item) })),
      "Data diperbarui"
    );

  const deleteCustomer = (id: string) => {
    if (window.confirm('Hapus pelanggan ini?')) {
      handleOptimizedAction(
        () => dbService.deleteCustomer(id),
        () => setState(prev => ({ ...prev, customers: prev.customers.filter(item => item.id !== id) })),
        "Pelanggan dihapus"
      );
    }
  };

  // PRODUCTS
  const addProduct = (p: Product) => 
    handleOptimizedAction(
      () => dbService.upsertProduct(p),
      () => setState(prev => ({ ...prev, products: [p, ...prev.products] })),
      "Barang ditambahkan"
    );

  const updateProduct = (p: Product) => 
    handleOptimizedAction(
      () => dbService.upsertProduct(p),
      () => setState(prev => ({ ...prev, products: prev.products.map(item => item.id === p.id ? p : item) })),
      "Barang diperbarui"
    );

  const deleteProduct = (id: string) => {
    if (window.confirm('Hapus barang ini?')) {
      handleOptimizedAction(
        () => dbService.deleteProduct(id),
        () => setState(prev => ({ ...prev, products: prev.products.filter(item => item.id !== id) })),
        "Barang dihapus"
      );
    }
  };

  // ORDERS
  const addOrder = async (o: Order) => {
    return await handleOptimizedAction(
      async () => {
        await dbService.upsertOrder(o);
        setView('orders');
      },
      () => setState(prev => ({ ...prev, orders: [o, ...prev.orders] })),
      "Order berhasil dibuat"
    );
  };

  const updateOrder = async (o: Order) => {
    return await handleOptimizedAction(
      () => dbService.upsertOrder(o),
      () => setState(prev => ({ ...prev, orders: prev.orders.map(item => item.id === o.id ? o : item) })),
      "Order diperbarui"
    );
  };

  const deleteOrder = (id: string) => {
    if (window.confirm('Hapus order ini?')) {
      handleOptimizedAction(
        () => dbService.deleteOrder(id),
        () => setState(prev => ({ ...prev, orders: prev.orders.filter(item => item.id !== id) })),
        "Order dihapus"
      );
    }
  };

  const viewInvoice = useCallback((order: Order) => {
    setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));
  }, []);

  if (initialLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white p-8">
      <Loader2 className="w-10 h-10 text-indigo-600 animate-spin" />
      <p className="mt-4 text-slate-400 font-black text-[10px] uppercase tracking-widest">Memulihkan Sesi...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row font-sans">
      {notification && (
        <div className={`fixed top-6 right-6 z-[100] flex items-center gap-4 px-6 py-4 rounded-2xl shadow-2xl border animate-in slide-in-from-right-5 fade-in duration-300 ${
          notification.type === 'success' ? 'bg-indigo-600 border-indigo-500 text-white' : 
          notification.type === 'error' ? 'bg-rose-600 border-rose-500 text-white' : 
          'bg-slate-800 border-slate-700 text-white'
        }`}>
          <div className="flex-shrink-0">
            {notification.type === 'success' && <CheckCircle2 size={20} />}
            {notification.type === 'error' && <X size={20} />}
            {notification.type === 'info' && <Info size={20} />}
          </div>
          <span className="text-sm font-bold tracking-tight">{notification.message}</span>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`w-72 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen shadow-2xl`}>
        <div className="p-8 flex flex-col gap-1">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl"><Package className="text-white w-5 h-5" /></div>
            <span className="text-lg font-black text-white tracking-tighter uppercase">Buku PO <span className="text-indigo-400">Online</span></span>
          </div>
        </div>

        <nav className="flex-1 px-6 pb-6 space-y-1.5 overflow-y-auto no-scrollbar">
          <NavItem icon={<LayoutDashboard size={18} />} label="Beranda" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />

          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Transaksi Utama</div>
          <NavItem icon={<ShoppingCart size={18} />} label="Daftar Order" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={18} />} label="Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />

          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-600">Data Master</div>
          <NavItem icon={<Users size={18} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={18} />} label="Katalog Barang" active={state.view === 'products'} onClick={() => setView('products')} />

          <div className="pt-10">
             <button 
              onClick={() => loadAllData(true)}
              disabled={isRefreshing}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-[10px] uppercase tracking-widest text-slate-500 hover:text-white transition-all"
             >
               <RefreshCw size={14} className={isRefreshing ? 'animate-spin' : ''} />
               Sinkron Manual
             </button>
          </div>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white/70 backdrop-blur-lg border-b h-16 flex items-center px-6 md:px-10 sticky top-0 z-30 justify-between shrink-0">
           <div className="flex items-center gap-4">
             <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden p-2 text-slate-600"><Menu size={24}/></button>
             <h2 className="text-sm font-black text-slate-900 uppercase tracking-widest">{state.view.replace('_', ' ')}</h2>
           </div>
           <div className="flex items-center gap-3">
              {isRefreshing && <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-indigo-500" /><span className="text-[9px] font-black text-indigo-500 uppercase">Sinkron...</span></div>}
              <span className="text-[10px] font-bold text-slate-400 hidden sm:block">
                {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}
              </span>
           </div>
        </header>

        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth">
          <div className="p-4 md:p-8 lg:p-12 max-w-7xl mx-auto">
            {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} onDeleteOrder={deleteOrder} />}
            {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
            {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
            {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
            {state.view === 'reports' && <Reports state={state} />}
            {state.view === 'invoice_detail' && state.activeOrder && (
              <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
                <button onClick={() => setView('orders')} className="group flex items-center gap-2 text-slate-500 hover:text-indigo-600 mb-6 font-bold text-xs uppercase tracking-widest transition-all">
                  <span>←</span> Kembali
