            )}
          </div>
        </div>
      </main>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}
    </div>
  );
};

const NavItem = React.memo(({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-sm transition-all duration-200 ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    <span className="shrink-0">{icon}</span>
    <span className="tracking-tight truncate">{label}</span>
  </button>
));

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, Trophy, 
  Calendar, Search, FileText, Image as ImageIcon, Clock,
  ListOrdered, ChevronRight, Hash, PieChart,
  ShoppingCart, ArrowDownToLine
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();

    if (type === 'today') {
      start.setHours(0,0,0,0);
    } else if (type === 'week') {
      start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
      start.setMonth(end.getMonth() - 1);
    } else if (type === 'year') {
      start.setFullYear(end.getFullYear() - 1);
    }

    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower);

      return matchesTime && matchesCustomer && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number, revenue: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0, revenue: 0 };
        salesMap[item.productId].qty += item.quantity;
        salesMap[item.productId].revenue += (item.quantity * item.unitPrice);
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders]);

  const totalOmzet = useMemo(() => filteredOrders.reduce((sum, o) => sum + (o.subtotal || 0), 0), [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#f1f5f9',
      logging: false,
      useCORS: true
    });
    const link = document.createElement('a');
    link.download = `Laporan_Bisnis_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#f1f5f9',
      logging: false,
      useCORS: true
    });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_Bisnis_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 pb-20 max-w-6xl mx-auto">
      {/* Configuration Header */}
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div>
             <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Konfigurasi Laporan</h3>
             <p className="text-slate-400 text-[11px] font-bold uppercase tracking-wider">Filter data dan pilih format ekspor</p>
           </div>
           <div className="flex gap-2 w-full md:w-auto">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-slate-600 text-[10px] font-black transition-all hover:bg-slate-50 active:scale-95"><ImageIcon size={14} /> JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-[10px] font-black transition-all shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end border-t border-slate-100 pt-6">
          <div className="md:col-span-4 space-y-3">
             <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
               <Clock size={12}/> Pilih Rentang Cepat
             </label>
             <div className="flex flex-wrap gap-1.5">
                {['today', 'week', 'month', 'year'].map((t) => (
                  <button 
                    key={t}
                    onClick={() => setPreset(t as any)} 
                    className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-black uppercase tracking-tighter hover:bg-indigo-600 hover:text-white transition-all"
                  >
                    {t === 'today' ? 'Hari Ini' : t === 'week' ? '7 Hari' : t === 'month' ? '30 Hari' : '1 Tahun'}
                  </button>
                ))}
             </div>
          </div>

          <div className="md:col-span-3 space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dari - Sampai</label>
            <div className="flex items-center gap-2">
              <input type="date" className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-200 text-xs font-bold text-slate-700 outline-none" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
              <span className="text-slate-300">-</span>
              <input type="date" className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-200 text-xs font-bold text-slate-700 outline-none" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
            </div>
          </div>

          <div className="md:col-span-3 space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Filter Pelanggan</label>
            <select className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-200 text-xs font-bold text-slate-700 outline-none" value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className="md:col-span-2 space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian</label>
            <div className="relative">
              <input type="text" placeholder="No. Inv..." className="w-full pl-8 pr-3 py-2 rounded-xl bg-slate-50 border border-slate-200 text-xs font-bold text-slate-700 outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-2.5 text-slate-300" size={14} />
            </div>
          </div>
        </div>
      </div>

      {/* Exportable Area */}
      <div ref={reportRef} className="bg-slate-100 p-4 md:p-10 rounded-[2.5rem] space-y-8 text-slate-900 border border-slate-200">
        {/* Report Brand Header */}
        <div className="bg-white p-8 md:p-12 rounded-[2rem] shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 border border-slate-100">
           <div className="text-center md:text-left">
              <h1 className="text-2xl font-black tracking-tighter uppercase text-slate-900">Laporan Aktivitas Bisnis</h1>
              <p className="text-indigo-500 text-[10px] font-black uppercase tracking-[0.4em]">Buku PO Online System</p>
           </div>
           <div className="flex items-center gap-4 bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100">
              <Calendar size={18} className="text-slate-300" />
              <div className="text-right">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Periode</p>
                <p className="text-xs font-bold text-slate-700">
                  {startDate ? new Date(startDate).toLocaleDateString('id-ID', { day: '2-digit', month: 'short' }) : 'Awal'} 
                  <span className="mx-2 text-slate-300">→</span> 
                  {endDate ? new Date(endDate).toLocaleDateString('id-ID', { day: '2-digit', month: 'short' }) : 'Kini'}
                </p>
              </div>
           </div>
        </div>

        {/* Global Summary Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
           {[
             { label: 'Total Omzet', value: `Rp ${totalOmzet.toLocaleString()}`, icon: <PieChart size={20}/>, color: 'text-indigo-600', bg: 'bg-white' },
             { label: 'Volume Pesanan', value: `${filteredOrders.length} Transaksi`, icon: <Hash size={20}/>, color: 'text-slate-800', bg: 'bg-white' },
             { label: 'Mitra Aktif', value: `${new Set(filteredOrders.map(o => o.customerId)).size} Pelanggan`, icon: <Users size={20}/>, color: 'text-slate-800', bg: 'bg-white' }
           ].map((s, i) => (
             <div key={i} className={`${s.bg} p-6 rounded-[2rem] border border-slate-200 shadow-sm flex items-center gap-5`}>
                <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-indigo-500 border border-slate-100">
                  {s.icon}
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{s.label}</p>
                  <h2 className={`text-xl font-black ${s.color} tracking-tight`}>{s.value}</h2>
                </div>
             </div>
           ))}
        </div>

        {/* Product Ranking */}
        <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
           <div className="flex items-center gap-3 mb-8">
             <div className="bg-amber-100 p-2 rounded-xl text-amber-600"><Trophy size={18}/></div>
             <h3 className="text-xs font-black text-slate-800 uppercase tracking-[0.3em]">Produk Paling Laku (Top 5)</h3>
           </div>
           <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-3">
