import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, CheckCircle2, Info, Loader2
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';
import { checkSupabaseConnection } from './lib/supabase';

interface Notification {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
}

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [initialLoading, setInitialLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);
  const loadAttempted = useRef(false);

  const showNotify = useCallback((message: string, type: 'success' | 'error' | 'info' | 'warning' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  }, []);

  const loadAllData = useCallback(async (isSilent = false) => {
    if (!isSilent) setInitialLoading(true);
    else setIsRefreshing(true);

    try {
      const connection = await checkSupabaseConnection();

      if (connection.connected) {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
        if (isSilent) showNotify("Data disinkronkan", "info");
      }
    } catch (e: any) {
      console.error("Data load error:", e);
      showNotify("Gagal sinkronisasi data", "error");
    } finally {
      setInitialLoading(false);
      setIsRefreshing(false);
    }
  }, [showNotify]);

  useEffect(() => {
    if (!loadAttempted.current) {
      loadAttempted.current = true;
      loadAllData();
    }
  }, [loadAllData]);

  const setView = useCallback((view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  }, []);

  const handleOptimizedAction = async (action: () => Promise<void>, updateState: () => void, successMsg: string) => {
    try {
      await action();
      updateState();
      showNotify(successMsg, 'success');
      return true;
    } catch (err: any) {
      showNotify(err.message || "Gagal memproses", 'error');
      return false;
    }
  };

  const addCustomer = (c: Customer) => handleOptimizedAction(() => dbService.upsertCustomer(c), () => setState(prev => ({ ...prev, customers: [c, ...prev.customers] })), "Pelanggan disimpan");
  const updateCustomer = (c: Customer) => handleOptimizedAction(() => dbService.upsertCustomer(c), () => setState(prev => ({ ...prev, customers: prev.customers.map(item => item.id === c.id ? c : item) })), "Data diperbarui");
  const deleteCustomer = (id: string) => { if (window.confirm('Hapus pelanggan ini?')) handleOptimizedAction(() => dbService.deleteCustomer(id), () => setState(prev => ({ ...prev, customers: prev.customers.filter(item => item.id !== id) })), "Pelanggan dihapus"); };

  const addProduct = (p: Product) => handleOptimizedAction(() => dbService.upsertProduct(p), () => setState(prev => ({ ...prev, products: [p, ...prev.products] })), "Barang ditambahkan");
  const updateProduct = (p: Product) => handleOptimizedAction(() => dbService.upsertProduct(p), () => setState(prev => ({ ...prev, products: prev.products.map(item => item.id === p.id ? p : item) })), "Barang diperbarui");
  const deleteProduct = (id: string) => { if (window.confirm('Hapus barang ini?')) handleOptimizedAction(() => dbService.deleteProduct(id), () => setState(prev => ({ ...prev, products: prev.products.filter(item => item.id !== id) })), "Barang dihapus"); };

  const addOrder = async (o: Order) => handleOptimizedAction(async () => { await dbService.upsertOrder(o); setView('orders'); }, () => setState(prev => ({ ...prev, orders: [o, ...prev.orders] })), "Order berhasil dibuat");
  const updateOrder = async (o: Order) => handleOptimizedAction(() => dbService.upsertOrder(o), () => setState(prev => ({ ...prev, orders: prev.orders.map(item => item.id === o.id ? o : item) })), "Order diperbarui");
  const deleteOrder = (id: string) => { if (window.confirm('Hapus order ini?')) handleOptimizedAction(() => dbService.deleteOrder(id), () => setState(prev => ({ ...prev, orders: prev.orders.filter(item => item.id !== id) })), "Order dihapus"); };

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (initialLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-100 p-8 text-slate-400">
      <Loader2 className="w-10 h-10 animate-spin mb-4" />
      <p className="text-[10px] font-black uppercase tracking-[0.2em]">Memuat Sistem...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col md:flex-row font-sans">
      {notification && (
        <div className={`fixed top-6 right-6 z-[100] flex items-center gap-4 px-6 py-4 rounded-2xl shadow-2xl border animate-in slide-in-from-right-5 ${
          notification.type === 'success' ? 'bg-indigo-600 border-indigo-500 text-white' : 
          notification.type === 'error' ? 'bg-rose-600 border-rose-500 text-white' : 
          'bg-slate-800 border-slate-700 text-white'
        }`}>
          <span className="text-sm font-bold">{notification.message}</span>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`w-72 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen shadow-2xl`}>
        <div className="p-8 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white"><Package size={20} /></div>
          <span className="text-lg font-black text-white uppercase tracking-tighter">Buku PO <span className="text-indigo-400">Online</span></span>
        </div>

        <nav className="flex-1 px-6 pb-6 space-y-1.5 overflow-y-auto no-scrollbar">
          <NavItem icon={<LayoutDashboard size={18} />} label="Beranda" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Transaksi</div>
          <NavItem icon={<ShoppingCart size={18} />} label="Daftar Order" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={18} />} label="Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />
          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Data Master</div>
          <NavItem icon={<Users size={18} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={18} />} label="Katalog Barang" active={state.view === 'products'} onClick={() => setView('products')} />
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white/80 backdrop-blur-lg border-b border-slate-200 h-16 flex items-center px-6 md:px-10 sticky top-0 z-30 justify-between">
           <div className="flex items-center gap-4">
             <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden text-slate-600"><Menu size={24}/></button>
             <h2 className="text-sm font-black text-slate-900 uppercase tracking-widest">{state.view.replace('_', ' ')}</h2>
           </div>
           {isRefreshing && <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-indigo-500" /><span className="text-[9px] font-black text-indigo-500">REFRESHING...</span></div>}
        </header>

        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth">
          <div className="p-4 md:p-8 lg:p-12 max-w-7xl mx-auto">
            {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} onDeleteOrder={deleteOrder} />}
            {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
            {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
            {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
            {state.view === 'reports' && <Reports state={state} />}
            {state.view === 'invoice_detail' && state.activeOrder && (
              <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <button onClick={() => setView('orders')} className="text-slate-500 hover:text-indigo-600 mb-6 font-bold text-xs uppercase tracking-widest">← Kembali</button>
                <InvoiceView order={state.activeOrder} onNotify={showNotify} />
              </div>
            )}
          </div>
        </div>
      </main>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-slate-900/40 z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-sm transition-all ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    {icon} <span>{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Trophy, Calendar, Search, FileText, Image as ImageIcon, 
  Clock, ListOrdered, Hash, PieChart, Users, ShoppingCart
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();
    if (type === 'today') start.setHours(0,0,0,0);
    else if (type === 'week') start.setDate(end.getDate() - 7);
    else if (type === 'month') start.setMonth(end.getMonth() - 1);
    else if (type === 'year') start.setFullYear(end.getFullYear() - 1);
    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);
      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || order.customerName.toLowerCase().includes(searchLower) || order.invoiceNumber.toLowerCase().includes(searchLower);
      return matchesTime && matchesCustomer && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, searchTerm]);

  const totalOmzet = useMemo(() => filteredOrders.reduce((sum, o) => sum + (o.subtotal || 0), 0), [filteredOrders]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const link = document.createElement('a');
    link.download = `Laporan_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 pb-20 max-w-6xl mx-auto">
      {/* Control Panel */}
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div>
             <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Filter Laporan</h3>
             <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider mt-1">Sesuaikan data yang ingin ditampilkan</p>
           </div>
           <div className="flex gap-2 w-full md:w-auto">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 rounded-xl text-slate-600 text-[10px] font-black hover:bg-slate-200 transition-all"><ImageIcon size={14} /> JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end border-t border-slate-100 pt-6">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rentang Cepat</label>
            <div className="flex gap-1">
              {['today', 'week', 'month'].map(t => (
                <button key={t} onClick={() => setPreset(t as any)} className="flex-1 px-2 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[9px] font-bold text-slate-600 uppercase hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-100 transition-all">
                  {t === 'today' ? 'Hari ini' : t === 'week' ? '7 Hari' : '30 Hari'}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Mulai - Selesai</label>
            <div className="flex items-center gap-1">
              <input type="date" className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={startDate} onChange={e => setStartDate(e.target.value)} />
              <input type="date" className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={endDate} onChange={e => setEndDate(e.target.value)} />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pelanggan</label>
            <select className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={filterCustomer} onChange={e => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian No. INV</label>
            <div className="relative">
              <input type="text" placeholder="Cari..." className="w-full pl-8 pr-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-2 text-slate-300" size={12} />
            </div>
          </div>
        </div>
      </div>

      {/* Exportable Area */}
      <div ref={reportRef} className="bg-slate-100 p-6 md:p-10 rounded-[2.5rem] space-y-6 text-slate-900 border border-slate-200 shadow-inner">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 border border-slate-100">
           <div className="text-center md:text-left">
              <h1 className="text-xl font-black tracking-tighter uppercase text-slate-900">Laporan Aktivitas Bisnis</h1>
              <p className="text-indigo-500 text-[9px] font-black uppercase tracking-[0.3em] mt-1">Buku PO Online System</p>
           </div>
           <div className="flex items-center gap-4 bg-slate-50 px-5 py-3 rounded-2xl border border-slate-100">
              <div className="text-right">
                <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Rentang Laporan</p>
                <p className="text-[11px] font-bold text-slate-700">
                  {startDate || 'Awal'} <span className="mx-1 text-slate-300">→</span> {endDate || 'Kini'}
                </p>
              </div>
           </div>
        </div>

        {/* Standarized Summary Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
           {[
             { label: 'Akumulasi Omzet', value: `Rp ${totalOmzet.toLocaleString()}`, icon: <PieChart size={18}/> },
             { label: 'Volume Transaksi', value: `${filteredOrders.length} Order`, icon: <ShoppingCart size={18}/> },
             { label: 'Mitra Aktif', value: `${new Set(filteredOrders.map(o => o.customerId)).size} Pelanggan`, icon: <Users size={18}/> }
           ].map((s, i) => (
             <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-indigo-500 border border-slate-100">
                  {s.icon}
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">{s.label}</p>
                  <h2 className="text-lg font-black text-slate-900 tracking-tight leading-none">{s.value}</h2>
                </div>
             </div>
           ))}
        </div>

        {/* Product Ranking */}
        <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm">
           <div className="flex items-center gap-2 mb-6">
             <Trophy size={16} className="text-amber-500"/>
             <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Peringkat Penjualan Produk</h3>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
              {productSales.slice(0, 5).map((p, i) => (
                <div key={i} className="p-3 rounded-xl border border-slate-100 bg-slate-50/50 text-center">
                   <p className="text-[9px] font-black text-amber-500 mb-1">RANK #0{i+1}</p>
                   <p className="text-[11px] font-bold text-slate-800 truncate mb-1">{p.name}</p>
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{p.qty} UNIT</p>
                </div>
              ))}
           </div>
        </div>

        {/* Detailed List */}
        <div className="bg-white rounded-[1.5rem] border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <ListOrdered size={16} className="text-indigo-500" />
              <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Rincian Log Transaksi</h3>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-white text-slate-400 text-[8px] font-black uppercase tracking-widest border-b border-slate-100">
                  <th className="px-6 py-4">Invoice / Tanggal</th>
                  <th className="px-6 py-4">Pelanggan</th>
                  <th className="px-6 py-4 text-right">Nilai (Rp)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredOrders.map(order => (
                  <tr key={order.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-3">
                      <p className="text-[11px] font-black text-slate-900">{order.invoiceNumber}</p>
                      <p className="text-[9px] text-slate-400 font-bold uppercase">{new Date(order.orderDate).toLocaleDateString('id-ID')}</p>
                    </td>
                    <td className="px-6 py-3">
                      <p className="text-[11px] font-bold text-slate-700">{order.customerName}</p>
                      <p className="text-[8px] text-slate-400 font-black uppercase tracking-tighter">{order.customerType}</p>
                    </td>
                    <td className="px-6 py-3 text-right">
                      <p className="text-[11px] font-black text-slate-900">{(order.subtotal || 0).toLocaleString()}</p>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
             <div>
               <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">TOTAL OMZET PERIODE INI</p>
               <h3 className="text-xl font-black text-indigo-400 tracking-tight">Rp {totalOmzet.toLocaleString()}</h3>
             </div>
             <div className="text-right">
                <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">Generated At</p>
                <p className="text-[10px] font-bold text-slate-400">{new Date().toLocaleString('id-ID')}</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;
